import{c as t,Q as a,j as n,m as s}from"./chunks/framework.BXc4yaFE.js";const l=JSON.parse('{"title":"TheSequence — 2026-04-23","description":"","frontmatter":{"title":"TheSequence — 2026-04-23","date":"2026-04-23T00:00:00.000Z","source":"TheSequence","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-23-thesequence.md","filePath":"research/ai-news/2026-04/2026-04-23-thesequence.md","lastUpdated":1779894392000}'),o={name:"research/ai-news/2026-04/2026-04-23-thesequence.md"};function r(i,e,c,h,p,u){return a(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="🔢-thesequence-—-2026-04-23" tabindex="-1">🔢 TheSequence — 2026-04-23 <a class="header-anchor" href="#🔢-thesequence-—-2026-04-23" aria-label="Permalink to &quot;🔢 TheSequence — 2026-04-23&quot;">​</a></h1><blockquote><p>165k+ 訂閱；ML / 企業 AI 應用週報，Jesus Rodriguez 主筆 來源：<a href="https://thesequence.substack.com/feed" target="_blank" rel="noreferrer">TheSequence</a></p></blockquote><hr><h2 id="the-sequence-opinion-848-the-agent-s-hands-cli-or-mcp" tabindex="-1"><a href="https://thesequence.substack.com/p/the-sequence-opinion-848-the-agents" target="_blank" rel="noreferrer">The Sequence Opinion #848: The Agent’s Hands: CLI or MCP?</a> <a class="header-anchor" href="#the-sequence-opinion-848-the-agent-s-hands-cli-or-mcp" aria-label="Permalink to &quot;[The Sequence Opinion #848: The Agent’s Hands: CLI or MCP?](https://thesequence.substack.com/p/the-sequence-opinion-848-the-agents)&quot;">​</a></h2><p><em>🔢 TheSequence | 2026-04-23</em></p><p>The most important question in agentic software is not “Which model?” It is “What can the model touch?”</p><p>A language model by itself is a strange kind of brain in a jar. It can predict, plan, summarize, and improvise, but it has no hands. The moment we give it tools, it becomes something else: not merely a chatbot, but an operator. It can read files, write code, open issues, call APIs, move tickets, delete emails, deploy infrastructure, or wake you up at 3 a.m. because a background workflow misread a calendar event.</p><p>So the real primitive of agentic systems is the interface between the model and the world.</p><p>Two candidates have emerged as the main bridge: the command-line interface, or CLI, and the Model Context Protocol, or MCP. They represent two different philosophies. CLI says: “The best tool interface already exists. It is the Unix process. Text in, text out, exit code, compose everything.” MCP says: “Agents need structured, discoverable, typed tools. Give them a protocol, schemas, resources, prompts, permissions, and a client-server architecture.”</p><p><a href="https://thesequence.substack.com/p/the-sequence-opinion-848-the-agents" target="_blank" rel="noreferrer"> Read more </a></p><hr>',11)])])}const m=t(o,[["render",r]]);export{l as __pageData,m as default};
